const letters = ['A', 'B', 'C', 'D']

function makeQuestions(section, count, offset, prefix) {
  return Array.from({ length: count }, (_, index) => {
    const answerIndex = (index + offset) % section.terms.length
    const answer = section.terms[answerIndex]
    const choices = [answer, ...[1, 2, 3].map((step) => section.terms[(answerIndex + step) % section.terms.length])]
    const rotation = index % choices.length
    const options = [...choices.slice(rotation), ...choices.slice(0, rotation)].map(([term]) => term)
    return {
      id: `${section.id}-${prefix}-${index + 1}`,
      objective: section.objective,
      domain: section.domain,
      prompt: `${section.title}: which term best matches this description — ${answer[1]}`,
      options,
      correctIndex: options.indexOf(answer[0]),
      explanation: `${answer[0]} is the best answer because it means ${answer[1].charAt(0).toLowerCase()}${answer[1].slice(1)}`,
    }
  })
}

function makeSection(section, tier) {
  const base = `t${tier.number}-${section.id}`
  const common = { required: true, domain: section.domain, objective: section.objective, difficulty: tier.difficulty }
  return {
    id: `${base}-section`,
    title: `Section ${section.number} · ${section.title}`,
    summary: section.summary,
    activities: [
      { id: base, type: 'lesson', title: section.title, duration: 12, ...common, summary: section.summary, learningObjectives: section.objectives, headings: section.headings, content: section.reading },
      { id: `${base}-scenario`, type: 'scenario', title: `Worked scenario · ${section.scenario.title}`, duration: 9, ...common, summary: section.scenario.summary, instructions: section.scenario.instructions, evidence: section.scenario.evidence, actions: section.scenario.actions, scoringRules: section.scenario.scoringRules, hints: section.scenario.hints, explanation: section.scenario.explanation },
      { id: `${base}-cards`, type: 'flashcards', title: `${section.title} flashcards`, duration: 9, ...common, summary: `Practice ${section.terms.length} essential terms and decisions.`, cards: section.terms },
      { id: `${base}-check`, type: 'quiz', title: `${section.title} knowledge check`, duration: 8, ...common, summary: 'Answer five coached questions with immediate explanations.', questions: makeQuestions(section, 5, 0, 'kc') },
      { id: `${base}-quiz`, type: 'quiz', title: `${section.title} section quiz`, duration: 12, ...common, summary: `Complete ten questions to finish ${section.title}.`, questions: makeQuestions(section, 10, 4, 'sq') },
    ],
  }
}

const term = (name, definition) => [name, definition]
const genericScenario = (title, focus) => ({
  title,
  summary: `Apply ${focus} to a realistic security decision.`,
  instructions: `Review the evidence, select the three actions that best reduce immediate and long-term risk, then compare your reasoning with the field explanation.`,
  evidence: [`A production service shows an unexpected security signal.`, `The service supports a time-sensitive business process.`, `Existing documentation and ownership information are incomplete.`],
  actions: [
    { id: 'preserve', label: 'Preserve relevant evidence and establish scope', correct: true },
    { id: 'contain', label: `Apply a targeted ${focus} control`, correct: true },
    { id: 'owner', label: 'Notify the accountable owner and record the decision', correct: true },
    { id: 'erase', label: 'Erase the affected system before collecting evidence', correct: false },
    { id: 'ignore', label: 'Wait for user reports before investigating', correct: false },
  ],
  scoringRules: { pointsPerCorrect: 1, penaltyPerIncorrect: 1, passingScore: 2 },
  hints: ['Protect evidence before making irreversible changes.', 'Prefer scoped containment over an unplanned outage.'],
  explanation: `Strong handling combines evidence preservation, proportionate containment, clear ownership, and documented follow-through. ${focus} is useful only when it supports the risk decision rather than becoming a checkbox.`,
})

const specs = [
  { tier: 2, id:'network', number:1, title:'Network attack surfaces', domain:2, objective:'2.2–2.4', summary:'Trace attacks through exposed services, protocols, and trust paths.', objectives:['Recognize common network attacks','Connect exposure to likely impact','Choose layered network mitigations'], headings:['Map the reachable surface','Spoofing and interception','Name and route manipulation','Availability attacks','Wireless exposure','Layer the response'], reading:['Attackers begin with what they can reach: public services, remote administration, wireless networks, partner links, and trusted internal paths. Inventory and exposure management turn that surface into something defenders can reason about.','Spoofing forges an identity or address, while on-path attacks place an adversary between communicating systems. Mutual authentication, protected protocols, certificate validation, and switched-network safeguards reduce these opportunities.','DNS poisoning redirects names, ARP poisoning corrupts local address resolution, and route manipulation changes packet paths. Secure configurations, monitoring, and authenticated routing or naming controls help reveal and prevent tampering.','Denial-of-service attacks exhaust bandwidth, state, or application resources. Rate limits, resilient capacity, filtering, content delivery networks, and upstream coordination reduce impact without assuming every request is legitimate.','Evil twins, weak wireless authentication, and unmanaged access points create alternate paths into a network. Strong enterprise authentication, wireless monitoring, segmentation, and user verification reduce the blast radius.','No network control is perfect. Minimize exposed services, patch reachable systems, authenticate sensitive traffic, segment trust zones, monitor behavior, and rehearse containment so one foothold does not become enterprise access.'], terms:[term('Attack surface','All reachable points where an attacker may attempt entry.'),term('On-path attack','Interception or alteration of traffic between parties.'),term('ARP poisoning','False local address-resolution messages used to redirect traffic.'),term('DNS poisoning','Corrupting name resolution to send users to the wrong destination.'),term('DDoS','Distributed traffic intended to exhaust a service or connection.'),term('Evil twin','A malicious wireless network impersonating a trusted one.'),term('Segmentation','Dividing networks to restrict communication and lateral movement.'),term('Rate limiting','Restricting request volume over time.'),term('Mutual authentication','Both communicating parties prove identity.'),term('Port scan','A probe that identifies reachable network services.'),term('VLAN hopping','Crossing logical network boundaries through configuration abuse.'),term('Replay attack','Reusing captured valid data to repeat an action.'),term('Protocol hardening','Disabling weak options and enforcing secure protocol settings.'),term('Network telemetry','Connection and traffic evidence used for detection.')], scenario:genericScenario('An exposed management service','network containment') },
  { tier:2,id:'vulnerabilities',number:2,title:'System and supply-chain vulnerabilities',domain:2,objective:'2.3',summary:'Recognize weaknesses across applications, platforms, devices, and suppliers.',objectives:['Classify common vulnerability sources','Prioritize exposure and impact','Reduce third-party and platform risk'],headings:['Weaknesses have context','Application flaws','Platform and device risk','Cloud configuration','Supply-chain trust','Prioritize remediation'],reading:['A vulnerability is meaningful in context: exploitability, exposure, privileges, affected data, and business impact determine urgency. A high severity score alone does not describe organizational risk.','Injection, insecure design, memory flaws, broken access control, and vulnerable dependencies can turn input or trust errors into compromise. Secure development, testing, code review, and runtime protections reduce risk at different stages.','Operating systems, mobile devices, IoT, embedded systems, and industrial technology have different patch and availability constraints. Compensating controls may be necessary when immediate replacement or patching is unsafe.','Cloud incidents often begin with exposed storage, excessive permissions, leaked secrets, or misunderstood provider responsibilities. Configuration assessment and policy automation help detect drift before it becomes exposure.','Suppliers, build systems, updates, and dependencies extend trust beyond the organization. Software inventories, signed releases, supplier assessment, and controlled build pipelines reduce opportunities for hidden compromise.','Prioritization combines severity with active exploitation, asset criticality, reachability, and available mitigations. Teams should document exceptions, verify remediation, and measure time at risk.'],terms:[term('CVE','A public identifier for a known vulnerability.'),term('CVSS','A standardized vulnerability severity scoring framework.'),term('Zero-day','A vulnerability exploited before an effective fix is available.'),term('Injection','Untrusted input interpreted as commands or queries.'),term('Buffer overflow','Writing beyond allocated memory boundaries.'),term('Misconfiguration','An unsafe or unintended system setting.'),term('Dependency','External software a system relies upon.'),term('SBOM','An inventory of software components in a product.'),term('Attack chain','Connected steps used to reach an objective.'),term('Compensating control','An alternate safeguard used when the preferred control is unavailable.'),term('Exposure','The degree to which a weakness is reachable.'),term('Patch management','The controlled process for evaluating and applying updates.'),term('Configuration drift','A system moving away from its approved baseline.'),term('Supply-chain attack','Compromise through a trusted supplier or dependency.')],scenario:genericScenario('A vulnerable vendor appliance','vulnerability prioritization')},
  { tier:2,id:'malware',number:3,title:'Malware behavior and defense',domain:2,objective:'2.4–2.5',summary:'Connect malware behavior and indicators to prevention and containment.',objectives:['Identify behavior across the attack lifecycle','Interpret host and network indicators','Choose containment that preserves evidence'],headings:['Behavior over labels','Delivery and execution','Persistence and privilege','Command and control','Impact and evasion','Break the chain'],reading:['Modern intrusions combine tools and behaviors, so defenders should describe what code does rather than depend on one malware label. Delivery, execution, persistence, control, discovery, movement, collection, and impact provide a reusable map.','Malicious attachments, scripts, drive-by downloads, poisoned updates, and exploited services can start execution. Filtering helps, but application control, patching, restricted scripting, and user-resistant workflows provide additional barriers.','Attackers create services, scheduled tasks, startup entries, accounts, or stolen tokens to survive. Least privilege and endpoint monitoring make those changes harder and more visible.','Command-and-control traffic may use common web protocols, encrypted channels, DNS, or cloud services. Egress controls and behavior analytics can reveal unusual destinations, timing, and data movement.','Ransomware encrypts or destroys data, spyware collects it, and rootkits hide activity. Obfuscation, living-off-the-land tools, and disabled security agents complicate detection.','Containment isolates affected systems, revokes compromised identity material, blocks malicious infrastructure, preserves evidence, and protects backups. Recovery requires verified clean restoration and lessons that improve prevention.'],terms:[term('Dropper','Code designed to install another malicious payload.'),term('Persistence','A method that maintains access across restarts or changes.'),term('Command and control','A channel used to direct compromised systems.'),term('Ransomware','Malware that denies access or threatens disclosure for payment.'),term('Rootkit','Tools that hide malicious privileged activity.'),term('Living off the land','Abusing legitimate system tools for malicious actions.'),term('IOC','An observable artifact associated with possible compromise.'),term('Behavioral detection','Detection based on actions rather than a known signature.'),term('EDR','Endpoint monitoring and response technology.'),term('Sandbox','An isolated environment for safely observing code.'),term('Quarantine','Restricting a suspicious file or system from normal interaction.'),term('Egress filtering','Controlling outbound network communication.'),term('Immutable backup','A backup protected from alteration for a defined period.'),term('Reimaging','Rebuilding a system from a trusted source.')],scenario:genericScenario('A rapidly encrypting endpoint','malware containment')},
  { tier:2,id:'social',number:4,title:'Social engineering and physical attacks',domain:2,objective:'2.2',summary:'Recognize manipulation, verify requests, and strengthen human-layer defenses.',objectives:['Identify manipulation techniques','Design verification-resistant workflows','Combine awareness with technical controls'],headings:['People are part of the system','Pressure and pretext','Message channels','Physical access','Design safer workflows','Learn without blame'],reading:['Social engineering exploits normal human behavior: trust, urgency, authority, curiosity, fear, and helpfulness. Effective defense changes workflows so a moment of persuasion cannot authorize high-impact action.','Pretexting builds a believable story; impersonation borrows authority; elicitation draws out information indirectly. Verification should use a separate trusted channel and known contact details.','Phishing can arrive through email, text, voice, QR codes, collaboration tools, or social media. Authentication-resistant workflows and reporting paths matter more than memorizing channel names.','Tailgating, shoulder surfing, badge theft, dumpster diving, and unattended devices bypass digital boundaries. Layered physical controls and clear challenge procedures reduce opportunity.','Payment changes, password resets, data releases, and privileged actions should require independent verification, separation of duties, and auditable approval. This turns awareness into resilient process design.','Training should be timely, role-specific, measurable, and psychologically safe. Reported attempts provide detection data; punishing reporters teaches silence and makes the organization easier to deceive.'],terms:[term('Pretexting','Using a fabricated story or identity to influence a target.'),term('Spear phishing','A tailored deceptive message aimed at a specific target.'),term('Whaling','Phishing directed at senior or high-value personnel.'),term('Smishing','Phishing delivered through text messaging.'),term('Vishing','Voice-based social engineering.'),term('Quishing','Phishing that uses a QR code.'),term('Baiting','Offering something enticing to prompt unsafe action.'),term('Tailgating','Following an authorized person into a controlled area.'),term('Shoulder surfing','Observing sensitive information directly.'),term('Elicitation','Drawing information out through conversation.'),term('Callback verification','Confirming a request through a known independent channel.'),term('Dual control','Requiring two people for a sensitive action.'),term('Security awareness','Education that helps people recognize and handle risk.'),term('Report rate','The proportion of simulated or real attacks users report.')],scenario:genericScenario('An urgent payment change','independent verification')},
  { tier:2,id:'identity-attacks',number:5,title:'Identity attacks and access defense',domain:2,objective:'2.4–2.5',summary:'Defend credentials, sessions, and access paths from abuse.',objectives:['Distinguish credential attack patterns','Protect authentication and recovery','Contain compromised sessions and privileges'],headings:['Identity is an attack surface','Guessing and reuse','Tokens and sessions','MFA attacks','Privilege pathways','Contain identity compromise'],reading:['Passwords, tokens, sessions, recovery processes, service accounts, and identity providers all create authentication paths. Defenders must protect the full lifecycle rather than only the login screen.','Brute force targets one account with many guesses, spraying tests common passwords across accounts, and stuffing reuses breached credentials. Rate limits, unique passwords, breached-password screening, and strong MFA address different parts of the problem.','Session cookies and access tokens can be stolen and replayed without knowing a password. Short lifetimes, device binding, secure storage, reauthentication, and revocation reduce their value.','Push fatigue, adversary-in-the-middle phishing, SIM swapping, and help-desk manipulation can bypass weaker MFA and recovery. Phishing-resistant authenticators and verified recovery processes improve assurance.','Excessive privileges, stale accounts, standing administration, and weak service-account controls turn one identity into broad access. Reviews and just-in-time elevation reduce blast radius.','Response revokes sessions and tokens, resets affected secrets, checks persistence and delegated access, reviews identity logs, and removes unauthorized changes. Password reset alone may leave the attacker active.'],terms:[term('Password spraying','Testing a few common passwords across many accounts.'),term('Credential stuffing','Reusing credentials stolen from another service.'),term('Brute force','Systematically trying many possible credentials.'),term('Session hijacking','Taking over an authenticated session.'),term('Token theft','Stealing reusable authentication or authorization material.'),term('MFA fatigue','Flooding a user with approval prompts.'),term('Phishing-resistant MFA','Authentication designed to resist credential relay and fake sites.'),term('Account recovery','The process used to regain access after losing an authenticator.'),term('Service account','A nonhuman identity used by software or automation.'),term('Standing privilege','Elevated access that remains continuously available.'),term('JIT access','Privilege granted only when needed and for limited time.'),term('Impossible travel','Logins whose timing and location cannot reasonably coexist.'),term('Session revocation','Invalidating active authentication sessions.'),term('Identity provider','A service that authenticates identities for other systems.')],scenario:genericScenario('A stolen cloud session','identity containment')},
  { tier:2,id:'hardening',number:6,title:'Hardening and layered mitigation',domain:4,objective:'4.1',summary:'Build, maintain, and verify secure system baselines.',objectives:['Create defensible baselines','Prioritize patching and isolation','Verify controls remain effective'],headings:['Start from a known state','Reduce functionality','Patch with context','Segment and isolate','Protect configuration','Measure and improve'],reading:['A secure baseline defines the approved configuration for a system role. It should be versioned, tested, automated where practical, and tied to an owner so drift becomes a visible operational event.','Disable unnecessary services, remove default accounts, restrict administrative interfaces, enforce least privilege, and allow only required software and communication. Less functionality means fewer opportunities for abuse.','Patch decisions account for exploitation, exposure, criticality, compatibility, and compensating controls. Emergency changes still need testing, approval, rollback, and verification.','Segmentation limits ordinary reachability; isolation removes a suspicious asset from normal interaction. Both controls need management paths that do not silently recreate broad trust.','Configuration management, signed packages, secrets protection, secure boot, and file integrity monitoring help preserve the intended state. Backups must be protected from the same privileges as production.','Compliance scans, vulnerability validation, attack simulation, and operational metrics show whether the baseline works. Exceptions should expire and be reviewed rather than becoming permanent undocumented policy.'],terms:[term('Secure baseline','An approved minimum configuration for a system role.'),term('Attack surface reduction','Removing unnecessary exposure and functionality.'),term('Application allow list','A policy permitting only approved software to execute.'),term('Patch window','An approved period for applying updates.'),term('Compensating control','An alternate safeguard used when direct remediation is delayed.'),term('Microsegmentation','Fine-grained restrictions between workloads.'),term('Isolation','Separating an asset from normal communication.'),term('Secure boot','Verifying trusted startup components before execution.'),term('File integrity monitoring','Detecting unexpected changes to protected files.'),term('Configuration management','Controlling and recording system settings over time.'),term('Drift','Deviation from an approved configuration.'),term('Exception','A documented, approved departure from policy.'),term('Rollback plan','Steps for safely reversing a failed change.'),term('Validation','Evidence that a remediation or control works as intended.')],scenario:genericScenario('A drifting server fleet','baseline enforcement')},
]

